const currentInspection = $("Mark as Processing").item.json;
const prevInspections = $input.all().map(i => i.json).filter(i => i.id !== currentInspection.id);

const prevSummary = prevInspections.length > 0
  ? JSON.stringify(prevInspections[0], null, 2)
  : 'אין ביקורות קודמות';

const prompt = `אתה עוזר לחברת כיבוי אש ישראלית. המנהל ביקש:

"${currentInspection.smart_request}"

פרטי ביקורת נוכחית:
- מזהה לקוח: ${currentInspection.customer_id}
- שם לקוח: ${currentInspection.customer_name || 'לא ידוע'}
- תאריך ביקורת: ${currentInspection.inspection_date}

ביקורת אחרונה (JSON):
${prevSummary}

בהתאם לבקשה, החזר JSON תקין בלבד (ללא הסבר) בפורמט:
{
  "form_types": ["1"],
  "copy_from_inspection_id": "prev_id_or_null",
  "notes": "הערות לביקורת",
  "form_data_override": {}
}`;

return [{ json: {
  prompt,
  inspection_id: currentInspection.id,
  customer_id: currentInspection.customer_id,
  inspection_date: currentInspection.inspection_date,
  filled_by: currentInspection.created_by_id || 'automation',
  copy_from_id: prevInspections.length > 0 ? prevInspections[0].id : null
}}];

const claudeText = $input.item.json.content[0].text;
let parsed;
try {
  const jsonMatch = claudeText.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(jsonMatch ? jsonMatch[0] : claudeText);
} catch(e) {
  parsed = { form_types: ['1'], copy_from_inspection_id: null, notes: '', form_data_override: {} };
}

const buildNode = $("Build Claude Prompt").item.json;

return { json: {
  form_types: parsed.form_types || ['1'],
  copy_from_inspection_id: parsed.copy_from_inspection_id || buildNode.copy_from_id,
  notes: parsed.notes || '',
  form_data_override: parsed.form_data_override || {},
  inspection_id: buildNode.inspection_id,
  customer_id: buildNode.customer_id,
  inspection_date: buildNode.inspection_date,
  filled_by: buildNode.filled_by
}};

const result = [];
for (const item of $input.all()) {
  const d = item.json;
  for (const ft of (d.form_types || ['1'])) {
    result.push({ json: {
      template_id: ft,
      customer_id: d.customer_id,
      filled_by: d.filled_by || 'automation',
      form_data: JSON.stringify(d.form_data_override || {}),
      status: 'draft',
      fill_date: d.inspection_date,
      notes: d.notes || '',
      inspection_id: d.inspection_id
    }});
  }
}
return result;
